SELECT SUM(file_size) AS total_file_size, LOG2(SUM(file_size)) AS log2_total_file_size
FROM data_downloads
WHERE file_format = 'CSV';

SELECT variation
FROM name_variations
WHERE popularity_score = (SELECT MAX(popularity_score) FROM name_variations);

SELECT file_format, SUM(file_size) AS total_file_size
FROM data_downloads
GROUP BY file_format;

SELECT SUM(count) AS total_count
FROM baby_names
WHERE year = 1880;

SELECT COUNT(*) 
FROM data_requests 
WHERE api_key_id IN (SELECT api_key_id FROM api_keys WHERE user_id = 0) AND status = 'completed';
